// Script Continued Below
function onLoad() {
	var dt_ooo;
	var ajax = new GlideAjax('ClientTaskInfo');

	if (typeof spModal != 'undefined' ) {
		dt_ooo = x_153465_discovert.DTech_Out_of_Office;
		// All UI Type Portal uses this.document, All UI Type Platform/Native uses top.document
		dt_ooo.init(spModal, this.document, ajax, g_form, g_scratchpad.taskScheduledooo, 
					g_scratchpad.messages, g_scratchpad.styleSheetLinks, 
					g_scratchpad.originalSuspenseDate);		
		setTimeout(_loadTaskRespondersOOO, 1000, dt_ooo);

	} else {
		ScriptLoader.getScripts(['x_153465_discovert.DTech_Out_of_Office.jsdbx'], function() {
			// STRY0130635 
			// All UI Type Portal uses this.document, Desktop only UI Type uses top.document, 
			dt_ooo = x_153465_discovert.DTech_Out_of_Office;
			dt_ooo.init(undefined, top.document, ajax, g_form, g_scratchpad.taskScheduledooo,
						g_scratchpad.messages, g_scratchpad.styleSheetLinks,
						g_scratchpad.originalSuspenseDate);
			dt_ooo.load_stylesheets_ui_native_only();
			setTimeout(_loadTaskRespondersOOO,1000);
		});
	}

	function _loadTaskRespondersOOO (){
		g_form.clearMessages();
		dt_ooo.load_task_response_ooo();
	}
}
